q(P,'廬山會議轉向反右的最嚴重後果是',['A.彭德懷被撤職','B.中斷了糾\"左\"進程，經濟困難進一步加劇','C.中蘇關係惡化','D.導致文革爆發'],1,'會後\"共產風\"再度颳起；1960年經濟各項指標跌至谷底。',['會議','影響'])

# 三年困難
q(P,'劉少奇在七千人大會上對三年困難原因的名言是',['A.\"七分天災，三分人禍\"','B.\"三分天災，七分人禍\"','C.\"全是天災\"','D.\"全為人禍\"'],1,'1962年1-2月七千人大會上劉少奇代表中央作報告，首次明確指出造成困難的主要原因是人為的政策失誤。',['會議','人物'])
q(P,'七千人大會(1962年1-2月)上毛澤東做了自我批評',['A.\"我完全錯了\"','B.\"凡是中央犯的錯誤，直接的歸我負責，間接的我也有份\"','C.\"大躍進是一個錯誤\"','D.\"我對經濟工作不懂\"'],1,'毛澤東做了有限度的自我批評，但同時強調要維護黨的團結，在肯定三面紅旗的前提下糾偏。',['會議','人物'])
q(P,'1960年全國總人口比上年淨減少了約多少人',['A.約100萬','B.約500萬','C.約1000萬','D.約3000萬'],2,'1960年死亡率從正常年份的10.8‰上升至25.43‰——正常年份的兩倍多。',['經濟','數據'])
q(P,'\"信陽事件\"是指',['A.自然災害引發的大面積饑荒','B.1959年冬至1960年春河南信陽地區因\"左\"傾錯誤導致的大面積非正常死亡(約100-105萬)','C.蘇聯撤走專家引發的工業停產','D.農村反抗集體化的起義'],1,'\"人禍甚於天災，是虛報、高徵購、暴力搜糧以及人為封鎖禁逃禁言的災難\"。',['事件'])
q(P,'三年困難時期承擔最大苦難的群體是',['A.城市工人','B.農村農民——特別是產糧區的農民','C.知識分子','D.軍隊'],1,'城鄉二元結構下城市居民的糧食定量得到優先保障，而農村人口既無糧食供應也無自由流動權利。',['經濟'])
q(P,'阿瑪蒂亞·森解釋饑荒的核心理論是',['A.糧食總量絕對不足','B.特定人群獲取糧食的\"權利\"失敗','C.自然災害不可抗拒','D.人口增長過快'],1,'他在《貧困與饑荒》中論證：饑荒很少是因為糧食總量絕對不足，而是因為特定人群獲取糧食的\"權利\"(entitlement)失敗。',['理論'])
q(P,'大饑荒中糧食分配的優先序是',['A.農村>城市','B.大城市>中等城市>小城鎮>農村','C.人人平等','D.按勞分配'],1,'\"饑荒程度從大城市到偏遠農村呈現明顯的梯度遞增——這不是自然條件的差異造成的，而是制度設計的結果。\"',['經濟'])
q(P,'1960年9月中共中央接連發出三個糧食相關指示的內容不包括',['A.壓低農村和城市的糧標準','B.整頓城市糧食統銷','C.壓縮食油銷量','D.取消統購統銷'],3,'三個指示的目標都是進一步壓縮消費、保障最低供應，而非取消統購統銷。',['經濟','時間'])
q(P,'\"八字方針\"的內容是',['A.調整、鞏固、充實、提高','B.鼓足幹勁、力爭上游、多快好省','C.獨立自主、自力更生、艱苦奮鬥、勤儉建國','D.調整、改革、整頓、提高'],0,'1961年正式提出——\"調整\"是核心(調整國民經濟的比例關係)。',['經濟','政策'])
q(P,'1961-1963年精簡城鎮人口的\"六二壓\"共減少城鎮人口約',['A.約500萬','B.約1000萬','C.約2600萬','D.約5000萬'],2,'將原從農村招來的工人下放回農村，以減少商品糧供應壓力。',['經濟','數據'])
q(P,'第二次\"包產到戶\"發生於',['A.1956-1957年','B.1961-1962年(安徽\"責任田\"/\"救命田\")','C.1964年','D.1978年'],1,'安徽的\"田間生產管理責任制\"，簡稱\"責任田\"——是饑荒的應對措施。1962年八屆十中全會被批判為\"單幹風\"。',['經濟','時間'])
q(P,'八屆十中全會召開於',['A.1960年1月','B.1961年6月','C.1962年9月','D.1963年5月'],2,'毛澤東在會上重提階級鬥爭，提出\"千萬不要忘了階級鬥爭\"，批判\"單幹風\"\"翻案風\"\"黑暗風\"。',['會議','時間'])
q(P,'毛澤東在八屆十中全會上提出的著名口號是',['A.\"以階級鬥爭為綱\"','B.\"千萬不要忘了階級鬥爭\"','C.\"造反有理\"','D.\"抓革命促生產\"'],1,'這一口號標誌著七千人大會後的糾\"左\"方向再次逆轉。',['會議','口號'])
q(P,'\"四清\"(小四清)最初的內容是',['A.清政治、清經濟、清組織、清思想','B.清賬目、清倉庫、清財物、清工分','C.清思想、清文化、清作風、清紀律','D.清地、清富、清反、清壞'],1,'針對農村基層幹部多吃多佔、貪污盜竊的行為——保定\"小四清\"經驗。',['運動'])
q(P,'《二十三條》(1965.1)將\"四清\"重新定義為',['A.清賬目、清倉庫、清財物、清工分','B.清政治、清經濟、清組織、清思想','C.清貪污、清浪費、清官僚主義、清分散主義','D.清反革命、清右派、清壞分子、清特務'],1,'從\"小四清\"到\"大四清\"——從經濟清理轉向政治清理。',['運動','文件'])
q(P,'《二十三條》中最關鍵的提法是',['A.\"以階級鬥爭為綱\"','B.\"這次運動的重點，是整黨內那些走資本主義道路的當權派\"','C.\"團結95%以上的幹部\"','D.\"增產是搞好運動的標準之一\"'],1,'這一句把鬥爭矛頭直接指向黨內高層，被認為是\"文革的預演\"。',['文件','政策'])
q(P,'城鄉社會主義教育運動中\"前十條\"(1963.5)主要由誰主持起草',['A.劉少奇','B.毛澤東','C.周恩來','D.鄧小平'],1,'是社教運動的綱領性文件，強調\"當前中國社會中出現了嚴重的尖銳的階級鬥爭\"。',['文件','人物'])
q(P,'社教運動中\"後十條\"(1963.9)主要由誰主持起草',['A.毛澤東','B.鄧小平','C.劉少奇','D.彭真'],1,'相比\"前十條\"更溫和——強調團結95%以上的幹部和群眾，明確運動不能妨礙生產。',['文件','人物'])
